// Get data from prior nodes
const productsQueryResults = $('Products Query').all();

let facetsQueryResults = [];
try {
  facetsQueryResults = $('Facets Query').all();
} catch (e) {
  facetsQueryResults = []; // Facets Query not executed (that's OK)
}

// Extract products records
const productsData = productsQueryResults[0]?.json?.records || productsQueryResults[0]?.json || [];
const productRecords = Array.isArray(productsData) ? productsData : [productsData];

// total_count (ALL matches), fallback to returned length
const totalCount =
  productRecords[0]?.fields?.total_count ??
  productRecords[0]?.total_count ??
  productRecords.length;

// --- Helpers ---
function bufferToBool(value) {
  if (value && typeof value === 'object' && value.type === 'Buffer' && Array.isArray(value.data) && value.data.length > 0) {
    const char = String.fromCharCode(value.data[0]);
    const c = char.toUpperCase();
    if (['T', 'Y', '1'].includes(c)) return true;
    if (['F', 'N', '0'].includes(c)) return false;
  }
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  if (typeof value === 'string') {
    const s = value.trim().toLowerCase();
    if (['true', 't', 'yes', 'y', '1'].includes(s)) return true;
    if (['false', 'f', 'no', 'n', '0'].includes(s)) return false;
  }
  return Boolean(value);
}

function normalizeProduct(record) {
  const fields = record.fields || record;
  return {
    sku: fields.sku,
    unit_name: fields.unit_name,
    name: fields.name,
    price: fields.price,
    height_ft: fields.height_ft,
    width_ft: fields.width_ft,
  };
}




// --- Normalize returned products (typically LIMIT 5) ---
const products = productRecords.map(normalizeProduct);

// --- Determine mode based on TOTAL count ---
let mode;
if (totalCount === 0) mode = 'none';
else if (totalCount === 1) mode = 'exact';
else if (totalCount <= 5) mode = 'full';
else if (totalCount <= 20) mode = 'guided';
else mode = 'narrow';

// --- Facets built from Facets Query (ALL matches) ---
const FACET_FIELDS = ['design', 'height_ft', 'width_ft', 'color', 'is_picket'];

let facets = null;
let suggested_filter = null;

if (totalCount > 5 && facetsQueryResults.length > 0) {
  const facetsData = facetsQueryResults[0]?.json?.records || facetsQueryResults[0]?.json || [];
  const facetRecords = Array.isArray(facetsData) ? facetsData : [facetsData];

  facets = {};

  // Group facet records by field
  for (const rec of facetRecords) {
    const r = rec.fields || rec;
    const field = r.field;
    const value = r.value;
    const cnt = r.cnt;

    if (!field || value === null || value === undefined || value === '') continue;
    if (!FACET_FIELDS.includes(field)) continue;

    if (!facets[field]) facets[field] = { values: [], counts: [] };
    facets[field].values.push(value);
    facets[field].counts.push(cnt);
  }

  // Remove fields with only 1 value
  for (const field of Object.keys(facets)) {
    if (facets[field].values.length <= 1) delete facets[field];
  }

  // Find most discriminating field
  let bestField = null;
  let bestScore = 0;

  for (const [field, data] of Object.entries(facets)) {
    const maxCount = Math.max(...data.counts);
    const score = 1 - (maxCount / totalCount);
    if (score > bestScore && data.values.length >= 2) {
      bestScore = score;
      bestField = field;
    }
  }

  suggested_filter = bestField;
}

// --- Build response ---
const response = {
  mode,
  total_count: totalCount,
  products: products.slice(0, 5),
};

if (facets && Object.keys(facets).length > 0) {
  response.facets = facets;
  response.suggested_filter = suggested_filter;
}

if (mode === 'none') {
  response.message = "No products found matching your criteria.";
}

return [{ json: response }];

// Get all incoming items
const items = $('When Executed from MCP Trigger Call').all();

function notEmpty(value) {
  if (value === undefined || value === null) return false;
  if (typeof value === 'string' && value.trim() === '') return false;
  return true;
}

const FAMILY_CODE_TEMP_FENCE = 6;

const TABLE_NAME = 'Products_summary_active_description_family_code_name_price_sku_unit_code';

// Temporary Fence columns (based on current dataset)
const PRODUCT_COLUMNS = [
  'sku',
  'name',
  'price',
  'unit_name',
  'height_ft',
  'width_ft'
].join(', ');

// Facets for Temporary Fence
const FACET_FIELDS = [
  'unit_name',
  'height_ft',
  'width_ft'
];

// Numeric facet fields (so we don’t do != '' on numbers)
const NUMERIC_FACETS = new Set(['height_ft', 'width_ft', 'price']);

const out = items.map(item => {
  const q = item.json.query || item.json || {};

  // --- WHERE construction ---
  const where = [];
  const args = [];

  // 🔒 HARD-CODED family_code for Temporary Fence
  where.push('family_code = ?');
  args.push(FAMILY_CODE_TEMP_FENCE);

  // unit_name
  if (notEmpty(q.unit_name)) {
    where.push('LOWER(unit_name) = LOWER(?)');
    args.push(q.unit_name);
  }

  // height_ft
  if (notEmpty(q.height_ft) && Number(q.height_ft) !== 0) {
    where.push('height_ft = ?');
    args.push(Number(q.height_ft));
  }

  // width_ft
  if (notEmpty(q.width_ft) && Number(q.width_ft) !== 0) {
    where.push('width_ft = ?');
    args.push(Number(q.width_ft));
  }

  // PRICE RANGE
  if (notEmpty(q.price_gte) && Number(q.price_gte) !== 0) {
    where.push('price >= ?');
    args.push(Number(q.price_gte));
  }

  if (notEmpty(q.price_lte) && Number(q.price_lte) !== 0) {
    where.push('price <= ?');
    args.push(Number(q.price_lte));
  }

  // ACTIVE default = true (keep consistent with other families)
  const active = typeof q.active === 'boolean' ? q.active : true;
  where.push('active = ?');
  args.push(active);

  const whereClause = ' WHERE ' + where.join(' AND ');

  // --- ORDER BY ---
  const orderParts = [];
  const priceOrder = q.price_order === 'asc' ? 'asc' : 'desc';
  orderParts.push(priceOrder === 'asc' ? 'price ASC' : 'price DESC');
  orderParts.push('unit_name', 'height_ft', 'width_ft');

  const orderBy = ' ORDER BY ' + orderParts.join(', ');

  // --- Products query: limited to 5 ---
  const productsSql =
    `SELECT ${PRODUCT_COLUMNS}, ` +
    `(SELECT COUNT(*) FROM ${TABLE_NAME}${whereClause}) as total_count ` +
    `FROM ${TABLE_NAME}${whereClause} ` +
    orderBy +
    ` LIMIT 5`;

  // --- Facets query: ALL matches ---
  const facetsSql = FACET_FIELDS.map(field => {
    const nonEmptyCheck = NUMERIC_FACETS.has(field)
      ? `${field} IS NOT NULL`
      : `${field} IS NOT NULL AND ${field} != ''`;

    return (
      `SELECT '${field}' as field, ${field} as value, COUNT(*) as cnt ` +
      `FROM ${TABLE_NAME}${whereClause} ` +
      `AND ${nonEmptyCheck} ` +
      `GROUP BY ${field}`
    );
  }).join(' UNION ALL ');

  // Args for facets (repeat per UNION subquery)
  const facetsArgs = [];
  for (let i = 0; i < FACET_FIELDS.length; i++) {
    facetsArgs.push(...args);
  }

  return {
    json: {
      ...item.json,
      productsSql,
      productsArgs: [...args, ...args], // productsSql uses where twice
      facetsSql,
      facetsArgs,
    },
  };
});

return out;
